import { Hono } from 'hono';
import { z, ZodError } from 'zod';

const app = new Hono();

// Define the schema for the request body
const renameTeamSchema = z.object({
  oldName: z.string(),
  newName: z.string()
});

app.put('/rename-team', async (c) => {
  try {
    // Parse the request body using the defined schema
    const { oldName, newName } = await c.req.json(renameTeamSchema);

    // Check if the user is an admin (this is a placeholder for actual authentication logic)
    const isAdmin = c.env.ADMIN_USERS.includes(c.req.user.id); // Assuming `c.req.user` contains user information

    if (!isAdmin) {
      return c.json({ error: 'Unauthorized' }, 403);
    }

    // Logic to rename the team (this is a placeholder for actual database logic)
    const success = await c.env.TEAMS.update(oldName, newName);

    if (success) {
      return c.json({ message: 'Team renamed successfully' });
    } else {
      return c.json({ error: 'Failed to rename team' }, 500);
    }
  } catch (error) {
    if (error instanceof ZodError) {
      return c.json({ error: 'Invalid request body', details: error.issues }, 400);
    }
    return c.json({ error: 'Internal server error' }, 500);
  }
});

export default app;

